#include <numeric>
#include <iostream>
#include <vector>
#include <queue>
#include <limits>
using namespace std;

class Solution {
public:
    vector<int> dijkstra(int n, int src, vector<vector<pair<int, int>>>& graph) {
        vector<int> distances(n, -1);
        distances[src] = 0;
        priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
        pq.push({0, src});

        while (!pq.empty()) {
            int curr_dist = pq.top().first;
            int curr_node = pq.top().second;
            pq.pop();

            if (curr_dist > distances[curr_node]) {
                continue;
            }

            for (const auto& neighbor_weight : graph[curr_node]) {
                int neighbor = neighbor_weight.first;
                int weight = neighbor_weight.second;
                int distance = curr_dist + weight;

                if (distances[neighbor] == -1 || distance < distances[neighbor]) {
                    distances[neighbor] = distance;
                    pq.push({distance, neighbor});
                }
            }
        }

        return distances;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    int src;
    cin >> src;
    int m;
    cin >> m;
    vector<vector<pair<int, int>>> graph(n);
    for (int i = 0; i < m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        graph[u].push_back({v, w});
    }
    Solution sol;
    vector<int> ans = sol.dijkstra(n, src, graph);
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
